package com.clashcoach.player;
import javax.persistence.*; import java.time.Instant; import java.util.UUID;
@Entity @Table(name="player_snapshots") public class PlayerSnapshot { @Id private UUID id; @ManyToOne(fetch=FetchType.LAZY) @JoinColumn(name="player_id",nullable=false) private Player player; @Column(name="captured_at",nullable=false) private Instant capturedAt; @Column(name="experience_level",nullable=false) private int experienceLevel; @Column(nullable=false) private int trophies; @Column(name="heroes_json",nullable=false,columnDefinition="jsonb") private String heroesJson; @Column(name="created_at",nullable=false) private Instant createdAt; protected PlayerSnapshot(){} public PlayerSnapshot(Player player, PlayerData data, String heroesJson){id=UUID.randomUUID();this.player=player;capturedAt=Instant.now();experienceLevel=data.getExperienceLevel();trophies=data.getTrophies();this.heroesJson=heroesJson;createdAt=capturedAt;} public UUID getId(){return id;} public Player getPlayer(){return player;} public Instant getCapturedAt(){return capturedAt;} public int getExperienceLevel(){return experienceLevel;} public int getTrophies(){return trophies;} public String getHeroesJson(){return heroesJson;} }
